// ============================================================
//  STATE
// ============================================================
const S={step:1,maxStep:1,co:'',batch:'',imgs:[],trainees:[]};

// ============================================================
//  INIT
// ============================================================
window.addEventListener('DOMContentLoaded',()=>{
    try{const c=JSON.parse(localStorage.getItem('red_cfg')||'{}');if(c.co)document.getElementById('cfg-co').value=c.co;if(c.batch)document.getElementById('cfg-batch').value=c.batch;}catch(e){}
    const z=document.getElementById('upzone');
    z.addEventListener('dragover',e=>{e.preventDefault();z.classList.add('over')});
    z.addEventListener('dragleave',()=>z.classList.remove('over'));
    z.addEventListener('drop',e=>{e.preventDefault();z.classList.remove('over');addFiles(e.dataTransfer.files)});
    /* Wire file input — onchange attribute removed for CSP compliance */
    const fi=document.getElementById('file-in');if(fi)fi.addEventListener('change',e=>pickFiles(e));
    /* Wire lightbox close-on-backdrop-click */
    const lb=document.getElementById('lightbox');if(lb)lb.addEventListener('click',e=>{if(e.target===e.currentTarget)e.currentTarget.classList.remove('on')});
});

/* ── EVENT DELEGATION (CSP-safe — replaces all inline onclick handlers) ── */
function toggleRawBox(){const b=document.getElementById('raw-box');if(b)b.classList.toggle('on')}
function copyOcrText(){navigator.clipboard.writeText((document.getElementById('raw-box')||{}).textContent||'').then(()=>toast('Copied!','ok'))}
function _coerceAttendanceDays(v){return v.trim()===''?'N/A':(isNaN(parseInt(v,10))?v:(parseInt(v,10)||0))}

document.addEventListener('click',function(e){
    const el=e.target.closest('[data-action]');
    if(!el)return;
    const a=el.dataset.action;
    if(!a)return;
    if(a==='navStep'){const s=+el.dataset.s;if(s)navStep(s);}
    else if(a==='cancelOCR')cancelOCR();
    else if(a==='doneStep1')doneStep1();
    else if(a==='extractFromScreenshots')extractFromScreenshots();
    else if(a==='toggleRawBox')toggleRawBox();
    else if(a==='copyOcrText')copyOcrText();
    else if(a==='go'){const s=+el.dataset.step;if(s)go(s);}
    else if(a==='skipScreenshots')skipScreenshots();
    else if(a==='doneStep2')doneStep2();
    else if(a==='addTrainee')addTrainee();
    else if(a==='recalcAll')recalcAll();
    else if(a==='genReport')genReport();
    else if(a==='startOver')startOver();
    else if(a==='printReport')window.print();
    else if(a==='dlPDF')dlPDF();
    else if(a==='rmImg'){e.stopPropagation();rmImg(el.dataset.id);}
    else if(a==='toggleCard'){const i=+el.dataset.i;toggleCard(i);}
    else if(a==='rmTrainee'){e.stopPropagation();rmTrainee(+el.dataset.i);}
    else if(a==='recalc')recalc(+el.dataset.i);
    else if(a==='regenText')regenText(+el.dataset.i);
    else if(a==='regenComments')regenComments(+el.dataset.i);
});

/* ── CHANGE DELEGATION for trainee card fields ── */
document.addEventListener('change',function(e){
    const el=e.target;
    const i=el.dataset.i!=null?+el.dataset.i:-1;
    if(i<0)return;
    if(el.dataset.score){us(i,el.dataset.score,el.value);return;}
    if(el.dataset.field){
        let val=el.value;
        if(el.dataset.coerce==='attendanceDays')val=_coerceAttendanceDays(val);
        else if(el.dataset.coerce==='parseInt')val=parseInt(val)||0;
        uf(i,el.dataset.field,val);
    }
});

// ============================================================
//  TOAST
// ============================================================
function toast(msg,type='info'){
    const c=document.getElementById('toast-box'),t=document.createElement('div');
    t.className=`toast toast-${type}`;t.textContent=msg;c.appendChild(t);
    setTimeout(()=>{t.classList.add('out');setTimeout(()=>t.remove(),300)},3000);
}

// ============================================================
//  NAVIGATION
// ============================================================
function go(s){
    if(s<1||s>4)return;
    if(s===4){document.getElementById('app-shell').style.display='none';document.getElementById('report-view').style.display='block'}
    else{document.getElementById('app-shell').style.display='block';document.getElementById('report-view').style.display='none'}
    for(let i=1;i<=3;i++){const el=document.getElementById('s'+i);if(el)el.style.display=i===s?'block':'none'}
    if(s>S.maxStep)S.maxStep=s;
    document.querySelectorAll('.dot').forEach(d=>{
        const n=+d.dataset.s;d.classList.remove('now','done');
        if(n===s)d.classList.add('now');else if(n<s||n<=S.maxStep)d.classList.add('done');
    });
    document.querySelectorAll('.dline').forEach(l=>{const n=+l.dataset.l;l.classList.toggle('done',n<s||n<S.maxStep)});
    S.step=s;
}
function navStep(s){if(s<=S.maxStep)go(s)}

