// ============================================================

let _ocrCancelled=false;
let _ocrTimeoutId=null;
function cancelOCR(){
    _ocrCancelled=true;
    if(_ocrTimeoutId){clearTimeout(_ocrTimeoutId);_ocrTimeoutId=null;}
    document.getElementById('ocr-overlay').classList.remove('on');
    toast('Extraction cancelled','info');
}

// Resize image to max dimension for API efficiency
function resizeImageForOCR(dataUrl,maxDim){
    return new Promise(resolve=>{
        const img=new Image();
        img.onload=()=>{
            const scale=Math.min(1,maxDim/Math.max(img.width,img.height,1));
            const w=Math.round(img.width*scale)||1,h=Math.round(img.height*scale)||1;
            const c=document.createElement('canvas');
            c.width=w;c.height=h;
            c.getContext('2d').drawImage(img,0,0,w,h);
            // 0.75 quality keeps base64 payload small enough for the 10MB body limit
            resolve(c.toDataURL('image/jpeg',0.75));
        };
        img.onerror=()=>resolve(dataUrl); // fallback: return original if load fails
        img.src=dataUrl;
    });
}

function ocrStep(n,state){
    for(let i=1;i<=4;i++){
        const el=document.getElementById('os-'+i);
        if(i<n){el.className='ocr-step done';el.querySelector('.sico').textContent='✅'}
        else if(i===n){el.className='ocr-step active';el.querySelector('.sico').textContent=state==='done'?'✅':'⏳'}
        else{el.className='ocr-step';el.querySelector('.sico').textContent='⏳'}
    }
}
function ocrProg(msg,pct){
    document.getElementById('ocr-msg').textContent=msg;
    document.getElementById('ocr-bar').style.width=pct+'%';
    document.getElementById('ocr-pct').textContent=Math.round(pct)+'%';
}

// Image preprocessing — enhances contrast for OCR accuracy
function ocrPreprocess(dataUrl){
    return new Promise(resolve=>{
        const img=new Image();
        img.onload=()=>{
            const c=document.createElement('canvas');
            // Scale up for better OCR (aim for ~300 DPI equivalent)
            const scale=Math.max(2,Math.min(4,2400/Math.max(img.width,img.height)));
            c.width=img.width*scale;c.height=img.height*scale;
            const ctx=c.getContext('2d');
            ctx.imageSmoothingEnabled=false;
            ctx.drawImage(img,0,0,c.width,c.height);

            const id=ctx.getImageData(0,0,c.width,c.height),d=id.data;

            // Step 1: Convert to grayscale and detect if dark or light theme
            const gray=new Float32Array(c.width*c.height);
            let totalBright=0;
            for(let i=0,j=0;i<d.length;i+=4,j++){
                gray[j]=0.299*d[i]+0.587*d[i+1]+0.114*d[i+2];
                totalBright+=gray[j];
            }
            const avgBright=totalBright/(c.width*c.height);
            const isDark=avgBright<128;

            // Step 2: If dark theme, invert to black text on white background
            if(isDark){
                for(let j=0;j<gray.length;j++) gray[j]=255-gray[j];
            }

            // Step 3: Local adaptive threshold (Sauvola-inspired)
            // Use a simplified approach: compute local mean in 15x15 blocks
            const w=c.width,h=c.height;
            const blockSize=Math.max(15,Math.round(Math.min(w,h)/80)|1);
            const halfBlock=blockSize>>1;

            // Build integral image for fast local mean
            const integral=new Float64Array((w+1)*(h+1));
            for(let y=0;y<h;y++){
                let rowSum=0;
                for(let x=0;x<w;x++){
                    rowSum+=gray[y*w+x];
                    integral[(y+1)*(w+1)+(x+1)]=integral[y*(w+1)+(x+1)]+rowSum;
                }
            }

            function localMean(x,y){
                const x1=Math.max(0,x-halfBlock),y1=Math.max(0,y-halfBlock);
                const x2=Math.min(w-1,x+halfBlock),y2=Math.min(h-1,y+halfBlock);
                const area=(x2-x1+1)*(y2-y1+1);
                const sum=integral[(y2+1)*(w+1)+(x2+1)]-integral[y1*(w+1)+(x2+1)]
                         -integral[(y2+1)*(w+1)+x1]+integral[y1*(w+1)+x1];
                return sum/area;
            }

            // Step 4: Apply adaptive binarization with bias toward keeping text
            const k=0.15; // Sauvola bias
            for(let y=0;y<h;y++){
                for(let x=0;x<w;x++){
                    const idx=y*w+x;
                    const px=gray[idx];
                    const mean=localMean(x,y);
                    // Threshold: pixel is text (dark) if it's darker than local mean adjusted by k
                    const threshold=mean*(1-k);
                    const out=px<threshold?0:255;
                    const pi=idx*4;
                    d[pi]=d[pi+1]=d[pi+2]=out;
                }
            }

            ctx.putImageData(id,0,0);
            resolve(c.toDataURL('image/png'));
        };
        img.src=dataUrl;
    });
}

// Main extraction function — uses Gemini Vision API
async function extractFromScreenshots(){
    if(!S.imgs.length){toast('Upload screenshots first','err');return}

    const ov=document.getElementById('ocr-overlay');
    ov.classList.add('on');
    _ocrCancelled=false;
    if(_ocrTimeoutId){clearTimeout(_ocrTimeoutId);_ocrTimeoutId=null;}
    ocrProg('Preparing images...',5);ocrStep(1);

    try{
        const allTrainees=[];
        ocrStep(1,'done');

        for(let i=0;i<S.imgs.length;i++){
            if(_ocrCancelled){ov.classList.remove('on');return;}

            const pct=10+Math.round((i/S.imgs.length)*65);
            ocrProg('Analyzing image '+(i+1)+' of '+S.imgs.length+' with AI...',pct);
            ocrStep(2);

            // Resize to max 1024px to keep payload manageable (well under 10MB body limit)
            const resized=await resizeImageForOCR(S.imgs[i].url,1024);
            const matchB64=resized.match(/^data:(image\/[a-zA-Z+]+);base64,(.+)$/);
            if(!matchB64){toast('Invalid image format for image '+(i+1),'err');ov.classList.remove('on');return;}
            const mimeType=matchB64[1];
            const b64=matchB64[2];

            if(_ocrCancelled){ov.classList.remove('on');return;}

            const prompt='Look at this image carefully. It is a screenshot of a training management system.\n'+
                'Your task: extract every trainee/person you can see in the image.\n\n'+
                'Output a JSON array where each trainee is an object with these keys:\n'+
                '  name (string - full name, required)\n'+
                '  mapping (number 0-5 or null)\n'+
                '  productKnowledge (number 0-5 or null)\n'+
                '  softSkills (number 0-5 or null)\n'+
                '  presentability (number 0-5 or null)\n'+
                '  attendanceDays (integer or null)\n'+
                '  absent (integer or null)\n'+
                '  assessmentOutcome (one of: "Excellent","Very Good","Good","Average","Passed","Failed" or "")\n'+
                '  comments (string)\n'+
                '  batch (string)\n'+
                '  company (string)\n\n'+
                'If scores appear as fractions like "4/5" use the numerator (4).\n'+
                'If you see a table, extract each row as a separate trainee.\n'+
                'If you see a card/detail view, extract that single trainee.\n'+
                'Do not include header rows or empty rows.\n'+
                'Respond with ONLY the JSON array, no explanations, no markdown fences.\n'+
                'Example: [{"name":"Ahmed Ali","mapping":4,"productKnowledge":3,"softSkills":5,"presentability":4,"attendanceDays":10,"absent":1,"assessmentOutcome":"Good","comments":"","batch":"32","company":"RED"}]\n'+
                'If no trainee data is visible at all, respond with exactly: []';

            let resp;
            try{
                resp=await fetch('/api/gemini',{
                    method:'POST',
                    headers:{'Content-Type':'application/json'},
                    body:JSON.stringify({
                        messages:[{role:'user',parts:[
                            {text:prompt},
                            {inlineData:{mimeType,data:b64}}
                        ]}],
                        generationConfig:{maxOutputTokens:4096}
                    })
                });
            }catch(netErr){
                throw new Error('Network error: '+(netErr&&netErr.message?netErr.message:'connection failed'));
            }

            if(!resp.ok){
                const errData=await resp.json().catch(()=>({}));
                throw new Error(errData.error||'AI service returned '+resp.status);
            }

            const result=await resp.json();
            const raw=(result.text||'').trim();
            // Strip markdown code fences if present, then extract JSON array
            let cleaned=raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```\s*$/,'').trim();
            // If the model wrapped in an object, try to find the array inside
            if(!cleaned.startsWith('[')){
                const arrMatch=cleaned.match(/(\[[\s\S]*\])/);
                if(arrMatch)cleaned=arrMatch[1];
            }
            console.log('[OCR] raw response for image',i+1,':',cleaned.slice(0,200));
            try{
                const parsed=JSON.parse(cleaned);
                const arr=Array.isArray(parsed)?parsed:[parsed];
                arr.forEach(t=>{if(t&&typeof t.name==='string'&&t.name.trim())allTrainees.push(t);});
            }catch(parseErr){
                console.warn('[OCR] JSON parse failed for image',i+1,cleaned,parseErr);
                // Non-fatal — continue to next image
            }
        }

        ocrStep(2,'done');ocrStep(3);
        ocrProg('Processing extracted data...',82);

        if(allTrainees.length===0){
            ocrProg('No trainee data found',100);ocrStep(3,'done');ocrStep(4);
            setTimeout(()=>{
                ov.classList.remove('on');
                toast('No trainee data found. Try clearer images or enter data manually.','err');
            },800);
            return;
        }

        // Map Gemini JSON to internal trainee format
        S.trainees=allTrainees.map(t=>{
            const mp=clampScore(t.mapping);
            const pk=clampScore(t.productKnowledge);
            const ss=clampScore(t.softSkills);
            const pr=clampScore(t.presentability);
            return{
                name:(t.name||'').trim(),
                company:(t.company&&t.company.trim())||S.co||'',
                batch:(t.batch&&t.batch.trim())||('Batch '+S.batch),
                overallScore:0,
                rawAssessmentOutcome:t.assessmentOutcome||'',
                assessmentResult:'',
                badgeClass:'b-gray',
                overallAssessment:'',
                scores:{
                    presentability:{score:pr,max:5},
                    softSkills:{score:ss,max:5},
                    mapping:{score:mp,max:5},
                    productKnowledge:{score:pk,max:5},
                    techScorePercent:0,softScorePercent:0,totalCore:0,
                    professionalConductRating:{score:0,max:10}
                },
                attendance:{
                    late:'N/A',
                    attendanceDays:t.attendanceDays!=null?parseInt(t.attendanceDays,10):'N/A',
                    absent:t.absent!=null?parseInt(t.absent,10):0,
                    missedContent:'N/A'
                },
                comments:t.comments||''
            };
        });

        S.trainees.forEach((_,i)=>recalc(i));
        S.trainees.forEach(t=>{
            if(t.name){
                t.overallAssessment=genAssessment(t);
                if(!t.comments)t.comments=genComments(t);
            }
        });

        ocrStep(3,'done');ocrStep(4,'done');
        ocrProg('Done! '+S.trainees.length+' trainee(s) extracted',100);

        setTimeout(()=>{
            ov.classList.remove('on');
            renderRefPanel();renderCards();go(3);
            toast('Extracted '+S.trainees.length+' trainee(s) from screenshots!','ok');
        },700);

    }catch(e){
        if(_ocrTimeoutId){clearTimeout(_ocrTimeoutId);_ocrTimeoutId=null;}
        console.error('[OCR] Error:',e);
        ov.classList.remove('on');
        const msg=e&&e.message?e.message:'unknown error';
        toast('AI extraction failed: '+msg+'. Try entering data manually.','err');
    }
}

// ============================================================
//  NOTION CARD VIEW PARSER  (one trainee per screenshot)
// ============================================================

// Returns true if this image's OCR text looks like a Notion detail card
function isCardView(text){
    const normalized=normFieldLabel(text);
    const fieldHits=[
        /\bmapp?ing\b/i,
        /\bsoft\s*skill/i,
        /\bproduct\s*know/i,
        /\bpresentab/i,
        /\bassessment\s*fo/i,
        /\battendance\b/i,
        /\babsen/i,
        /\binstructor\s*co/i,
        /\bbatch\b/i,
        /\bcompany\b/i
    ];
    let hits=0;
    for(const rx of fieldHits)if(rx.test(text)||rx.test(normalized))hits++;
    return hits>=3;
}

// Strip OCR noise from a candidate name string
function cleanOCRName(s){
    if(!s)return '';
    // Remove unicode box-drawing, Notion icons, emoji, dingbats, misc symbols
    s=s.replace(/[\u2000-\u2BFF\u{1F000}-\u{1FFFF}\u{E000}-\u{F8FF}\uFE00-\uFE0F\u200B-\u200F\u2028-\u202F]/gu,'').trim();
    // Remove leading punctuation/symbol clusters
    s=s.replace(/^[\[\]{}#@$%^&*()<>=+\-_~`'"!?|/\\;:,.]+\s*/,'').trim();
    // Remove common OCR artifacts that precede names (Notion page icons read as garbled text)
    // e.g., "Gd Ahmed Sayed" or "A& Mohamed Ali" or "a© Fatma Hassan"
    s=s.replace(/^[^\s]{1,3}[©®™&@#§¶†‡]+\s*/,'').trim();
    // Strip isolated 1-2 char garbage tokens before a capitalized name
    // Only strip if what follows starts with a capital letter (actual name)
    s=s.replace(/^[^\sa-zA-Z]{1,3}\s+(?=[A-Z])/,'').trim();
    // One more pass: strip any remaining single non-alpha token before a name
    s=s.replace(/^[^a-zA-Z\s]{1,2}\s+/,'').trim();
    // Fix common OCR substitutions in names
    s=s.replace(/\b0(?=[a-z])/g,'O');  // "0mar" → "Omar"
    s=s.replace(/\b1(?=[a-z])/g,'I');  // "1brahim" → "Ibrahim"
    // Fix "rn" → "m" isn't reliable, skip that
    // Capitalize first letter of each word if all lowercase
    if(s===s.toLowerCase()&&s.length>3){
        s=s.replace(/\b\w/g,c=>c.toUpperCase());
    }
    return s;
}

function normFieldLabel(line){
    return String(line||'')
        .toLowerCase()
        .replace(/0/g,'o')
        .replace(/[1|l]/g,'i')
        .replace(/5/g,'s')
        .replace(/8/g,'b')
        .replace(/[^a-z\s]/g,' ')
        .replace(/\s+/g,' ')
        .trim();
}

function isValidNameCandidate(value){
    const candidate=cleanOCRName(value).replace(/[.,;:]+$/,'').trim();
    if(candidate.length<4)return false;
    if(/\d/.test(candidate))return false;
    const compact=normFieldLabel(candidate).replace(/[^a-z]/g,'');
    if(!/[a-z]{2}/i.test(candidate))return false;
    if(/^(?:final|empty|roots?|batch|company|mapping|product|soft|present|attendance|absence|instructor|assessment|outcome|comments?|ratings?)$/i.test(candidate))return false;
    if(/(?:assessment|instructor|attendance|absence|outcome|product|mapping|presentability|softskills?)/i.test(compact))return false;
    const tokens=candidate.split(/\s+/).filter(Boolean);
    if(tokens.length<2)return false;
    const allowedShort=new Set(['al','el','de','da','di','la','le','bin','ibn','abu','om','ay','mo']);
    if(tokens.some(token=>token.length<2))return false;
    if(tokens.some(token=>token.length===2&&!allowedShort.has(token.toLowerCase())))return false;
    // Boost confidence: check if first token matches a common Arabic/English first name
    const commonFirstNames=new Set([
        'ahmed','mohamed','mohammed','mohammad','mahmoud','mustafa','omar','amr','ali','hassan','hussein',
        'ibrahim','ismail','youssef','yousuf','karim','khalid','khaled','tarek','tamer','hossam','walid',
        'sherif','ashraf','adel','nour','abdel','abdallah','ramy','sami','samir','ayman','ehab','hany',
        'magdy','maged','nader','osama','rahim','reda','said','shady','wael','yasser','ziad',
        'fatma','sara','sarah','mona','nada','noura','hana','dina','rana','rania','menna','mariam',
        'aya','yasmin','layla','salma','asmaa','esraa','heba','iman','reham','soha','omnia',
        'john','david','michael','james','robert','william','joseph','thomas','daniel','mark',
        'mary','jennifer','linda','elizabeth','susan','karen','nancy','lisa','betty','sandra'
    ]);
    if(commonFirstNames.has(tokens[0].toLowerCase()))return true;
    return true;
}

function bestNearbyName(lines,startIdx,searchRadius=3){
    // First pass: look forward
    for(let offset=1;offset<=searchRadius;offset++){
        const next=lines[startIdx+offset];
        if(!next)continue;
        const cleaned=cleanOCRName(next);
        if(isValidNameCandidate(cleaned))return cleaned;
        // Try partial: maybe just the first 2-3 title-case words are the name
        const partial=cleaned.match(/^([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})/);
        if(partial&&isValidNameCandidate(partial[1]))return partial[1];
    }
    // Second pass: look backward
    for(let offset=1;offset<=searchRadius;offset++){
        const prev=lines[startIdx-offset];
        if(!prev)continue;
        const cleaned=cleanOCRName(prev);
        if(isValidNameCandidate(cleaned))return cleaned;
        const partial=cleaned.match(/^([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})/);
        if(partial&&isValidNameCandidate(partial[1]))return partial[1];
    }
    return '';
}

// Find the first score value (0–5 range) on a field line, ignoring percent values
function firstScoreOnLine(line, nextLine){
    line=ocrNormText(line||'');
    nextLine=ocrNormText(nextLine||'');
    // Strip label text — scan for numbers not followed by %
    const re=/(?:^|[\s:])(\d+\.?\d*)(?!\s*%)/g;
    let m;
    while((m=re.exec(line))!==null){
        const v=parseFloat(m[1]);
        if(v>=0&&v<=5)return v;
    }
    // Try isolated fraction patterns: "3/5", "4.5/5"
    const fracM=line.match(/(\d+\.?\d*)\s*[/]\s*5/);
    if(fracM){const v=parseFloat(fracM[1]);if(v>=0&&v<=5)return v;}
    // Try the next line (value may be on separate line in OCR output)
    if(nextLine){
        const re2=/(?:^|[\s:])(\d+\.?\d*)(?!\s*%)/g;
        let m2;
        while((m2=re2.exec(nextLine))!==null){
            const v=parseFloat(m2[1]);
            if(v>=0&&v<=5)return v;
        }
    }
    return null;
}

// Normalise OCR text: fix common misreads that break number parsing
function ocrNormText(t){
    return t
        .replace(/,([\d])/g,'.$1')          // comma-decimal "3,5" → "3.5"
        .replace(/(\d)\.(\s+)(\d)/g,'$1.$3') // spaced decimal "3. 5" → "3.5"
        .replace(/\bO\b/g,'0')               // isolated O → 0
        .replace(/\bl\b/g,'1')               // isolated l → 1
        .replace(/\bS\b(?=\.?\d)/g,'5')      // S before digit → 5
        .replace(/(\d)[oO]/g,'$10')           // "3o" → "30" (zero after digit)
        .replace(/[oO](\d)/g,'0$1')           // "o3" → "03" (zero before digit)
        .replace(/\bI(\d)/g,'1$1')            // "I3" → "13"
        .replace(/(\d)I\b/g,'$11')            // "3I" → "31"
        .replace(/\bll\b/g,'11')              // "ll" → "11"
        .replace(/\bOO\b/g,'00');             // "OO" → "00"
}

// Robust score finder — tries patterns in order, returns first 0-5 match
function findScore(text,patterns){
    for(const p of patterns){
        const m=text.match(p);
        if(m){const v=parseFloat(m[1]);if(!isNaN(v)&&v>=0&&v<=5)return v;}
    }
    return null;
}

function isLikelyCardFieldLine(line){
    const normalized=normFieldLabel(line);
    return /^(?:assessment|instructor|mapping|product|tech|present|soft|overall|absence|attendance|company|batch)\b/i.test(normalized);
}

function collectFieldValue(lines,idx,labelRx,maxLookahead=2){
    const current=lines[idx]||'';
    let value=current.replace(labelRx,'').replace(/^[:\-.,\u2026\s]+/,'').trim();
    if(value&&!isLikelyCardFieldLine(value))return value;
    const parts=[];
    for(let offset=1;offset<=maxLookahead&&idx+offset<lines.length;offset++){
        const next=(lines[idx+offset]||'').trim();
        if(!next)continue;
        if(isLikelyCardFieldLine(next))break;
        parts.push(next);
    }
    return parts.join(' ').trim();
}

function titleCaseWords(s){
    return String(s||'').toLowerCase().replace(/\b\w/g,c=>c.toUpperCase());
}

function cleanOutcomeText(s){
    if(!s)return '';
    return titleCaseWords(
        s.replace(/["']/g,'')
            .replace(/^(?:was|is)\s+/i,'')
            .replace(/\s+/g,' ')
            .trim()
            .replace(/[.,;:]+$/,'')
    );
}

function normalizeAssessmentOutcome(raw,fallbackScore){
    const text=String(raw||'').trim().toLowerCase();
    if(/\baced\b/.test(text))return 'Aced';
    if(/\bexcellent\b/.test(text))return 'Excellent';
    if(/\bvery\s+good\b/.test(text))return 'Good';
    if(/\bgood\b/.test(text))return 'Good';
    if(/\bpass(?:ed)?\b/.test(text))return 'Passed';
    if(/\bfail(?:ed)?\b/.test(text))return 'Failed';
    if(typeof fallbackScore==='number'&&!Number.isNaN(fallbackScore))return tier(fallbackScore);
    return '';
}

function displayAssessmentOutcome(t){
    return t.rawAssessmentOutcome||t.assessmentResult||'';
}

function syncAssessmentState(t){
    t.assessmentResult=normalizeAssessmentOutcome(t.rawAssessmentOutcome,t.overallScore)||tier(t.overallScore);
    t.badgeClass=badgeCls(t.assessmentResult);
}

function extractSummaryData(fullText){
    const data={
        mapping:null,
        productKnowledge:null,
        softSkills:null,
        presentability:null,
        attendanceDays:null,
        absent:null,
        rawAssessmentOutcome:'',
        comments:''
    };

    data.mapping=findScore(fullText,[
        /mapp?ing\s*:\s*(\d+\.?\d*)/i,
        /scores?\s+included[\s\S]{0,80}?mapp?ing\s*:\s*(\d+\.?\d*)/i,
        /mapp?ing[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);
    data.productKnowledge=findScore(fullText,[
        /product\s*know[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /scores?\s+included[\s\S]{0,120}?product\s*know[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /product\s*know[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);
    data.presentability=findScore(fullText,[
        /present[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /scores?\s+included[\s\S]{0,120}?present[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /present[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);
    data.softSkills=findScore(fullText,[
        /soft\s*skill[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /scores?\s+included[\s\S]{0,120}?soft\s*skill[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /soft\s*skill[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);

    let match=fullText.match(/[Aa]ttendance\s+was\s+(\d+)\s+with\s+(no|zero|0)\s+absences?/i);
    if(match){
        data.attendanceDays=parseInt(match[1],10);
        data.absent=0;
    }else{
        match=fullText.match(/[Aa]ttendance\s+was\s+(\d+)\s+with\s+(\d+)\s+absences?/i);
        if(match){
            data.attendanceDays=parseInt(match[1],10);
            data.absent=parseInt(match[2],10);
        }
    }
    if(data.attendanceDays===null){
        match=fullText.match(/[Aa]ttended\s+all\s+(\d+)/i);
        if(match){
            data.attendanceDays=parseInt(match[1],10);
            data.absent=0;
        }
    }
    // More patterns: "attendance: 8", "attendance 8 days", "8 days attended"
    if(data.attendanceDays===null){
        match=fullText.match(/attendance\s*[:\-]\s*(\d+)/i)
           || fullText.match(/attendance\s+(\d+)\s*(?:days?)?/i)
           || fullText.match(/(\d+)\s+days?\s+attended/i);
        if(match){const v=parseInt(match[1],10);if(v>0&&v<=30)data.attendanceDays=v;}
    }
    // "absence: 0", "absent: 2", "0 absences", "2 absences"
    if(data.absent===null){
        match=fullText.match(/absences?\s*[:\-]\s*(\d+)/i)
           || fullText.match(/absent\s*[:\-]\s*(\d+)/i)
           || fullText.match(/(\d+)\s+absences?\b/i)
           || fullText.match(/(\d+)\s+absent\b/i);
        if(match){const v=parseInt(match[1],10);if(v>=0&&v<=30)data.absent=v;}
    }

    match=fullText.match(/(?:assessment\s+outcome|outcome|assessment)\s+was\s+["']?([A-Za-z][A-Za-z\s-]{2,30}?)(?=["'.,;]|\s+with\b|\s+and\b|$)/i);
    if(match)data.rawAssessmentOutcome=cleanOutcomeText(match[1]);

    match=fullText.match(/comments?\s+(?:highlighting|highlighted|noting|noted|mentioning)\s+([^.;]+)/i)
        || fullText.match(/with\s+comments?\s+([^.;]+)/i)
        || fullText.match(/instructor\s+comments?\s*[:\-]\s*([^.;]+)/i);
    if(match)data.comments=match[1].replace(/["']/g,'').trim();

    return data;
}

// Parse a single Notion detail card image into a trainee object (or null)
function parseCardView(text){
    const lines=text.split('\n').map(l=>l.trim()).filter(l=>l.length>0);
    // Normalise joined text for number parsing
    const fullText=ocrNormText(lines.join(' '));

    let name=null,mp=null,pk=null,ss=null,pr=null;
    let absent=0,attendanceDays='N/A',assessmentResult=null,rawAssessmentOutcome='',comments='';
    let company=S.co,batch='Batch '+S.batch;
    let gotAttFromAI=false;

    console.log('[CardParser] fullText preview:',fullText.substring(0,300));

    // ===========================================================
    // PASS 1 — AI summary paragraph (most reliable — clean typed text)
    // Notion AI writes: "Attendance was 8 with no absences. ...
    //   Ratings: Mapping: 3.5, Product Knowledge: 4.5, Presentability: 5, Soft Skills: 4.5."
    // ===========================================================

    const summaryData=extractSummaryData(fullText);
    // 1a. Scores — try the AI summary paragraph first, then explicit keyword:value searches
    const ratBlockM = fullText.match(/[Rr]atings?\s*[:\s,]+([\s\S]{10,120}?)(?:\s*\.\s|\s*$)/);
    const ratZone   = ratBlockM ? ratBlockM[1] : '';
    console.log('[CardParser] Ratings zone:',ratZone);

    // Score patterns: summary text, then explicit field/value pairs.
    mp=summaryData.mapping;
    if(mp===null)mp=findScore(fullText,[
        /mapp?ing\s*:\s*(\d+\.?\d*)/i,
        /mapp?ing[a-z.]*\s+(\d+\.?\d*)(?!\s*%)/i
    ]);
    pk=summaryData.productKnowledge;
    if(pk===null)pk=findScore(fullText,[
        /product\s*know[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /product\s*know[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);
    ss=summaryData.softSkills;
    if(ss===null)ss=findScore(fullText,[
        /soft\s*skill[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /soft\s*skill[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);
    pr=summaryData.presentability;
    if(pr===null)pr=findScore(fullText,[
        /present[a-z]*\s*:\s*(\d+\.?\d*)/i,
        /present[a-z.]*[\s:,]+(\d+\.?\d*)(?!\s*%)/i
    ]);
    console.log('[CardParser] Scores → mp:'+mp+' pk:'+pk+' ss:'+ss+' pr:'+pr);

    // 1b. Attendance / Absence from the summary paragraph
    if(summaryData.attendanceDays!==null){
        attendanceDays=summaryData.attendanceDays;
        gotAttFromAI=true;
    }
    if(summaryData.absent!==null)absent=summaryData.absent;
    if(!gotAttFromAI&&/no\s+absences?/i.test(fullText)){absent=0;gotAttFromAI=true;}
    console.log('[CardParser] Attendance → att:'+attendanceDays+' absent:'+absent+' (fromAI:'+gotAttFromAI+')');

    // 1c. Outcome / comments from the summary paragraph
    rawAssessmentOutcome=summaryData.rawAssessmentOutcome;
    assessmentResult=normalizeAssessmentOutcome(rawAssessmentOutcome);
    comments=summaryData.comments;

    // ===========================================================
    // PASS 2 — Line-by-line field parsing
    // Only fills fields still missing after the AI summary pass
    // ===========================================================
    for(let i=0;i<lines.length;i++){
        const L=lines[i];
        const NL=lines[i+1]||'';
        const labelNorm=normFieldLabel(L);

        // ---- Name from "Assessment Fo(rm)..." field ----
        if(/assessment\s*fo/.test(labelNorm)&&!/assessment\s*(out|o\b)/.test(labelNorm)){
            let val=collectFieldValue(lines,i,/^[\s\S]*?assessment\s*fo[^\s]*[.…]*\s*/i,2);
            val=cleanOCRName(val);
            if(isValidNameCandidate(val)){
                name=val;
            }else{
                // Try extracting title-case words from the collected value
                const titleMatch=val.match(/([A-Z][a-z]+(?:\s+[A-Za-z][a-z]+){1,3})/);
                if(titleMatch&&isValidNameCandidate(titleMatch[1])){
                    name=cleanOCRName(titleMatch[1]);
                }else{
                    // Try next line
                    let nv=cleanOCRName(NL);
                    if(isValidNameCandidate(nv)){name=nv;}
                    else{
                        // Try partial title-case from next line
                        const partNL=cleanOCRName(NL).match(/([A-Z][a-z]+(?:\s+[A-Za-z][a-z]+){1,3})/);
                        if(partNL&&isValidNameCandidate(partNL[1]))name=cleanOCRName(partNL[1]);
                    }
                    // Also try line after that
                    if(!name||name.length<2){
                        let nv2=cleanOCRName(lines[i+2]||'');
                        if(isValidNameCandidate(nv2))name=nv2;
                    }
                }
            }
        }

        // ---- Assessment outcome from "Assessment O(utcome)..." field ----
        if((!rawAssessmentOutcome||!assessmentResult)&&/assessment\s*o/.test(labelNorm)&&!/assessment\s*fo/.test(labelNorm)){
            const rawValue=cleanOutcomeText(collectFieldValue(lines,i,/^.*?assessment\s*o[^\s]*\.?\s*/i,2));
            if(rawValue){
                rawAssessmentOutcome=rawAssessmentOutcome||rawValue;
                assessmentResult=normalizeAssessmentOutcome(rawAssessmentOutcome);
            }
        }
        // Standalone outcome word on its own line (OCR sometimes splits label/value)
        if(!rawAssessmentOutcome){
            const rawStandalone=cleanOutcomeText(L);
            if(normalizeAssessmentOutcome(rawStandalone)){
                rawAssessmentOutcome=rawStandalone;
                assessmentResult=normalizeAssessmentOutcome(rawAssessmentOutcome);
            }
        }

        // ---- Instructor comments ----
        if(!comments&&/instructor\s*co/.test(labelNorm)){
            let val=collectFieldValue(lines,i,/^.*?instructor\s*co[^\s]*\.?\s*/i,3);
            if(val.length>5&&!isLikelyCardFieldLine(val))comments=val;
        }

        // ---- Scores (only fill gaps not already set from AI Ratings) ----
        if(mp===null&&/^mapping\b/.test(labelNorm)&&!/product/.test(labelNorm)){
            const v=firstScoreOnLine(L,NL);if(v!==null)mp=v;
        }
        if(pk===null&&(/^product\s*know/.test(labelNorm)||/^pk\b/.test(labelNorm))){
            const v=firstScoreOnLine(L,NL);if(v!==null)pk=v;
        }
        if(ss===null&&/soft\s*skill/.test(labelNorm)){
            const v=firstScoreOnLine(L,NL);if(v!==null)ss=v;
        }
        if(pr===null&&/^presentab/.test(labelNorm)){
            const v=firstScoreOnLine(L,NL);if(v!==null)pr=v;
        }

        // ---- Absence / Attendance (only if AI summary didn't already set them) ----
        if(!gotAttFromAI){
            if(/^absence\b/.test(labelNorm)||/^absent\b/.test(labelNorm)){
                const normLine=ocrNormText(L+' '+NL);
                const nums=normLine.match(/\b(\d+)\b/g);
                if(nums){
                    // Pick first number in sane range (0-30)
                    for(const n of nums){const v=parseInt(n,10);if(v>=0&&v<=30){absent=v;break;}}
                }
            }
            if(/^attendance\b/.test(labelNorm)&&!/absence|absent/.test(labelNorm)){
                const normLine=ocrNormText(L+' '+NL);
                const nums=normLine.match(/\b(\d+)\b/g);
                if(nums){
                    // Pick last number in sane range (1-30)
                    for(let ni=nums.length-1;ni>=0;ni--){const v=parseInt(nums[ni],10);if(v>0&&v<=30){attendanceDays=v;break;}}
                }
            }
        }

        // ---- Company ----
        if(/^company\b/.test(labelNorm)){
            let val=L.replace(/^.*?company\s*/i,'').replace(/[\u2000-\u2BFF\u{1F000}-\u{1FFFF}]/gu,'').trim();
            if(!val&&NL)val=NL.replace(/[\u2000-\u2BFF\u{1F000}-\u{1FFFF}]/gu,'').trim();
            if(val&&val.length>=2)company=val;
        }

        // ---- Batch ----
        if(/^batch\b/.test(labelNorm)){
            const bm=(L+' '+NL).match(/batch\s*\d+/i);
            if(bm)batch=bm[0].replace(/\s+/,' ');
        }
    }

    // ===========================================================
    // PASS 3 — Full-text fallback for anything still missing
    // ===========================================================

    // Name fallback — look for a proper noun sequence after the form field label
    if(!name||name.length<2){
        // Pattern: "Assessment Fo... [icon?] Name Here"
        const m=fullText.match(/assessment\s*fo[^\s.]*[.…]*\s+([A-Za-z][^\n\r]{2,40}?)(?:\s{2,}|$)/i);
        if(m){const v=cleanOCRName(m[1].trim());if(isValidNameCandidate(v))name=v;}
    }
    // Try extracting name using known-names anchor: look for common first names followed by another word
    if(!name||name.length<2){
        const nameRx=/\b((?:Ahmed|Mohamed|Mohammed|Mohammad|Mahmoud|Mustafa|Omar|Amr|Ali|Hassan|Hussein|Ibrahim|Ismail|Youssef|Karim|Khalid|Khaled|Tarek|Tamer|Hossam|Walid|Sherif|Ashraf|Nour|Abdel|Ramy|Sami|Ayman|Fatma|Sara|Sarah|Mona|Nada|Noura|Hana|Dina|Rana|Rania|Menna|Mariam|Aya|Yasmin|Layla|Salma|Heba|Iman)(?:\s+[A-Z][a-z]{1,}){1,3})/g;
        const candidates=[...fullText.matchAll(nameRx)];
        for(const c of candidates){
            const cv=cleanOCRName(c[1]);
            if(isValidNameCandidate(cv)){name=cv;break;}
        }
    }
    // Fallback around the outcome field position — the real name is often adjacent even if the form label OCR is mangled.
    if(!name||name.length<2){
        const outcomeIdx=lines.findIndex(line=>/assessment\s*o/i.test(line)||/^very\s+good$|^good$|^excellent$|^aced$|^passed?$|^failed?$/i.test(line));
        if(outcomeIdx>=0){
            const nearby=bestNearbyName(lines,outcomeIdx,3);
            if(nearby)name=nearby;
        }
    }
    // Final fallback — first multi-word title-case name in the entire text
    if(!name||name.length<2){
        const allTitleCase=[...fullText.matchAll(/\b([A-Z][a-z]{1,}(?:\s+[A-Z][a-z]{1,}){1,3})\b/g)];
        for(const m of allTitleCase){
            const candidate=cleanOCRName(m[1]);
            if(isValidNameCandidate(candidate)
                &&!/^(?:batch|company|mapping|product|skill|attend|absence|instructor|assessment|ratings?|final|empty|excellent|aced|good|passed?|failed?|roots)/i.test(candidate)){
                name=candidate;break;
            }
        }
    }
    console.log('[CardParser] Final → name:',name,'mp:',mp,'pk:',pk,'ss:',ss,'pr:',pr,'absent:',absent);

    if(!name||name.length<2)return null;
    if(mp===null&&pk===null&&ss===null&&pr===null)return null;

    mp=clampScore(mp||0);pk=clampScore(pk||0);ss=clampScore(ss||0);pr=clampScore(pr||0);
    assessmentResult=normalizeAssessmentOutcome(rawAssessmentOutcome)||assessmentResult||'Passed';

    return{
        name,company,batch,overallScore:0,
        rawAssessmentOutcome,
        assessmentResult,
        badgeClass:'b-gray',overallAssessment:'',
        scores:{
            presentability:{score:pr,max:5},
            softSkills:{score:ss,max:5},
            mapping:{score:mp,max:5},
            productKnowledge:{score:pk,max:5},
            techScorePercent:0,softScorePercent:0,totalCore:0,
            professionalConductRating:{score:0,max:10}
        },
        attendance:{late:'N/A',attendanceDays,absent,missedContent:'N/A'},
        comments:comments||''
    };
}

// ============================================================
//  SMART OCR TEXT PARSER
// ============================================================

function parseOCRText(raw){
    // ---- First pass: try per-image Notion card view ----
    const imageBlocks=raw.split(/---IMAGE-BREAK---/);
    const cardTrainees=[];
    for(const block of imageBlocks){
        if(isCardView(block)){
            console.log('[Parser] Detected card view in block, attempting card parser');
            const t=parseCardView(block);
            if(t){console.log('[Parser] Card parsed:',t.name);cardTrainees.push(t);}
        }
    }
    if(cardTrainees.length>0){
        // Deduplicate — fuzzy match names that OCR may have slightly corrupted
        const seen=new Map();
        for(const t of cardTrainees){
            const key=t.name.toLowerCase().replace(/\s+/g,' ').trim();
            // Check for near-duplicates (edit distance ≤ 2 or one name is substring of the other)
            let merged=false;
            for(const [existKey,existT] of seen){
                if(key===existKey||(key.length>5&&existKey.length>5&&(key.includes(existKey)||existKey.includes(key)))){
                    // Keep the one with more data (higher total score)
                    const existTotal=(existT.scores.mapping.score||0)+(existT.scores.productKnowledge.score||0)+(existT.scores.softSkills.score||0)+(existT.scores.presentability.score||0);
                    const newTotal=(t.scores.mapping.score||0)+(t.scores.productKnowledge.score||0)+(t.scores.softSkills.score||0)+(t.scores.presentability.score||0);
                    if(newTotal>existTotal)seen.set(existKey,t);
                    merged=true;break;
                }
            }
            if(!merged)seen.set(key,t);
        }
        return Array.from(seen.values());
    }

    // ---- Fallback: classic table/spreadsheet parser ----

    // Clean up common OCR artifacts
    let text=raw
        .replace(/[|¦│┃┆┊]/g,' ')  // table borders
        .replace(/[—–]/g,'-')       // dashes
        .replace(/\t+/g,'  ')       // tabs to spaces
        .replace(/[''`]/g,"'")      // smart quotes
        .replace(/[""]/g,'"');

    const lines=text.split('\n').map(l=>l.trim()).filter(l=>l.length>1);

    // Header keyword patterns
    const hdPatterns={
        name:/\b(name|trainee|student|employee|candidate)\b/i,
        pk:/\b(product|knowledge|pk|prod\.?\s*know)\b/i,
        map:/\b(mapp?ing|map)\b/i,
        ss:/\b(soft\s*skill|ss|communication)\b/i,
        pr:/\b(present|appearance|professionalism|professional)\b/i,
        late:/\b(late|tardy?|punctual)/i,
        absent:/\b(absent|absence|attend)/i,
        missed:/\b(miss|content)/i
    };

    // Score header for the entire header row
    let bestHeaderIdx=-1,bestHeaderScore=0;
    for(let i=0;i<Math.min(lines.length,15);i++){
        let score=0;
        for(const [k,rx] of Object.entries(hdPatterns)){
            if(rx.test(lines[i]))score++;
        }
        if(score>bestHeaderScore){bestHeaderScore=score;bestHeaderIdx=i}
    }

    console.log('[Parser] Best header line:',bestHeaderIdx,'score:',bestHeaderScore,bestHeaderIdx>=0?lines[bestHeaderIdx]:'none');

    // Determine column order from header if found
    let colOrder=null;
    if(bestHeaderScore>=2 && bestHeaderIdx>=0){
        colOrder=detectColumnOrder(lines[bestHeaderIdx]);
        console.log('[Parser] Detected column order:',colOrder);
    }

    // Parse data lines
    const trainees=[];
    const startLine=bestHeaderIdx>=0?bestHeaderIdx+1:0;

    for(let i=startLine;i<lines.length;i++){
        const line=lines[i];
        // Skip separator lines, empty-ish lines, image breaks
        if(/^[\-_=\s|+]+$/.test(line))continue;
        if(/IMAGE-BREAK/.test(line))continue;
        // Skip lines that look like headers or totals
        if(/\b(total|average|mean|score|assessment|result|overall|batch|company)\b/i.test(line)&&!/\b[A-Z][a-z]{2,}/g.test(line))continue;

        const t=parseDataRow(line,colOrder);
        if(t)trainees.push(t);
    }

    // Deduplicate by name
    const seen=new Map();
    for(const t of trainees){
        const key=t.name.toLowerCase().replace(/\s+/g,' ');
        if(!seen.has(key)||seen.get(key).overallScore<t.overallScore)seen.set(key,t);
    }

    return Array.from(seen.values());
}

function detectColumnOrder(headerLine){
    // Find position of each keyword in the header to determine order
    const fields=[
        {key:'pk',patterns:[/product/i,/knowledge/i,/pk/i]},
        {key:'map',patterns:[/mapp?ing/i]},
        {key:'ss',patterns:[/soft/i,/skill/i,/ss\b/i,/communicat/i]},
        {key:'pr',patterns:[/present/i,/appearance/i,/professional/i]},
        {key:'late',patterns:[/late/i,/tardy/i,/punctual/i]},
        {key:'absent',patterns:[/absent/i,/absence/i]},
        {key:'missed',patterns:[/miss/i]}
    ];

    const positions=[];
    for(const f of fields){
        let bestPos=Infinity;
        for(const p of f.patterns){
            const m=headerLine.match(p);
            if(m&&m.index<bestPos)bestPos=m.index;
        }
        if(bestPos<Infinity)positions.push({key:f.key,pos:bestPos});
    }

    positions.sort((a,b)=>a.pos-b.pos);
    return positions.map(p=>p.key);
}

function parseDataRow(line,colOrder){
    // A data row: text (name) followed by numbers
    // Could have a leading row number like "1" or "1."

    // Find where numbers start
    // Strategy: find first digit that's preceded by a space and looks like a score
    const numStartMatch=line.match(/\s(\d+\.?\d*)\s/);
    if(!numStartMatch)return null;

    let splitIdx=numStartMatch.index;
    let namePart=line.substring(0,splitIdx).trim();
    let numPart=line.substring(splitIdx).trim();

    // Clean up name: remove leading row numbers like "1.", "1)", "01"
    namePart=namePart.replace(/^\d{1,3}[\.\)\-\s]+/,'').trim();
    // Remove trailing special chars
    namePart=namePart.replace(/[^a-zA-Z\u0600-\u06FF\s]+$/,'').trim();

    if(!namePart||namePart.length<2)return null;

    // Skip if name looks like a header
    if(/^(name|trainee|student|total|average|score|product|mapping|soft|present|performance|area|metric)\b/i.test(namePart))return null;
    // Skip if name is all numbers or single char
    if(/^\d+$/.test(namePart)||namePart.length<2)return null;

    // Extract numbers from numPart, fixing OCR errors in the number zone only
    let cleanNums=numPart
        .replace(/\bO\b/g,'0')     // isolated O -> 0
        .replace(/\bo\b/g,'0')     // isolated o -> 0
        .replace(/\bl\b/g,'1')     // isolated l -> 1
        .replace(/\bI\b(?=[\s\d])/g,'1')  // I before space/digit -> 1
        .replace(/,(\d)/g,'.$1')   // comma as decimal -> dot
        .replace(/N\s*[\/\\]\s*A/gi,'NAN'); // Mark N/A as NAN for later

    const nums=[];
    const re=/\d+\.?\d*/g;
    let m;
    while((m=re.exec(cleanNums))!==null)nums.push(parseFloat(m[0]));

    if(nums.length<2)return null;

    // Check for N/A in original line
    const hasNA=/n\s*[\/\\]?\s*a/i.test(numPart);

    // Map numbers to fields
    let pk=0,mp=0,ss=0,pr=0,late='N/A',absent=0,missed='N/A';

    if(colOrder&&colOrder.length>=2){
        // Use detected column order
        const scoreNums=extractScoreSequence(nums);
        const mapping={pk:0,map:1,ss:2,pr:3};
        const scoreFields=colOrder.filter(k=>['pk','map','ss','pr'].includes(k));
        for(let i=0;i<scoreFields.length&&i<scoreNums.length;i++){
            const f=scoreFields[i];
            if(f==='pk')pk=scoreNums[i];
            else if(f==='map')mp=scoreNums[i];
            else if(f==='ss')ss=scoreNums[i];
            else if(f==='pr')pr=scoreNums[i];
        }
        // Attendance from remaining
        const attFields=colOrder.filter(k=>['late','absent','missed'].includes(k));
        const attStart=scoreFields.length;
        const attNums=nums.slice(attStart);
        for(let i=0;i<attFields.length;i++){
            const val=attNums[i];
            if(attFields[i]==='absent'&&val!=null)absent=Math.round(val);
            else if(attFields[i]==='late'&&val!=null)late=val;
        }
    }else{
        // No header detected — use heuristic
        const result=heuristicMap(nums);
        pk=result.pk;mp=result.mp;ss=result.ss;pr=result.pr;
        absent=result.absent;late=result.late;
    }

    if(hasNA){late='N/A';missed='N/A'}

    // Validate scores
    pk=clampScore(pk);mp=clampScore(mp);ss=clampScore(ss);pr=clampScore(pr);
    if(pk===0&&mp===0&&ss===0&&pr===0)return null; // all zeros = probably not a real row

    return{
        name:namePart,company:S.co,batch:'Batch '+S.batch,overallScore:0,
        rawAssessmentOutcome:'',assessmentResult:'Passed',badgeClass:'b-gray',overallAssessment:'',
        scores:{
            presentability:{score:pr,max:5},softSkills:{score:ss,max:5},
            mapping:{score:mp,max:5},productKnowledge:{score:pk,max:5},
            techScorePercent:0,softScorePercent:0,totalCore:0,
            professionalConductRating:{score:0,max:10}
        },
        attendance:{late:late,attendanceDays:'N/A',absent:absent,missedContent:missed},
        comments:''
    };
}

function extractScoreSequence(nums){
    // Find the first run of numbers that are in 0-5 range (individual scores)
    // Skip a leading row number if present
    let start=0;
    // If first number looks like a row number (integer 1-50, followed by numbers in 0-5)
    if(nums.length>4&&nums[0]===Math.floor(nums[0])&&nums[0]>=1&&nums[0]<=50){
        if(nums[1]>=0&&nums[1]<=5)start=1;
    }
    const result=[];
    for(let i=start;i<nums.length;i++){
        if(nums[i]>=0&&nums[i]<=5){
            result.push(nums[i]);
            if(result.length>=4)break;
        }else if(result.length>0){
            // Hit a non-score number (like a total or percentage)
            break;
        }
    }
    return result;
}

function heuristicMap(nums){
    // Without header, assume: [maybe-row#] PK, Map, SS, PR, [totals...], [late, absent]
    const scores=extractScoreSequence(nums);
    while(scores.length<4)scores.push(0);

    // Look for attendance at the end of all numbers
    let absent=0,late='N/A';
    // After the 4 scores, skip any large numbers (totals/percentages)
    // Then small numbers at the end are attendance
    const afterScores=[];
    let foundBig=false,scoreCount=0;
    let start=0;
    if(nums.length>4&&nums[0]===Math.floor(nums[0])&&nums[0]>=1&&nums[0]<=50)start=1;
    for(let i=start;i<nums.length;i++){
        if(scoreCount<4&&nums[i]>=0&&nums[i]<=5){scoreCount++;continue}
        if(scoreCount>=4)afterScores.push(nums[i]);
    }
    // The last 1-3 small integers in afterScores could be attendance
    const smallEnd=afterScores.filter(n=>n>=0&&n<=30&&n===Math.floor(n));
    if(smallEnd.length>=2){absent=smallEnd[smallEnd.length-1];late=smallEnd[smallEnd.length-2]}
    else if(smallEnd.length===1){absent=smallEnd[0]}

    return{pk:scores[0],mp:scores[1],ss:scores[2],pr:scores[3],absent,late};
}

function clampScore(v){
    v=parseFloat(v)||0;
    // Round to nearest 0.5
    v=Math.round(v*2)/2;
    return Math.max(0,Math.min(5,v));
}

// ============================================================
//  SMART TEXT ENGINE — generates everything from numbers
// ============================================================
function tier(score){
    if(score>=90)return'Aced';if(score>=80)return'Excellent';if(score>=70)return'Good';if(score>=60)return'Passed';return'Failed';
}
function badgeCls(r){return{'Aced':'b-green','Excellent':'b-blue','Good':'b-yellow','Passed':'b-gray','Failed':'b-red'}[r]||'b-gray'}

function genAssessment(t){
    const name=t.name||'The trainee';
    const res=displayAssessmentOutcome(t)||t.assessmentResult;
    const ov=t.overallScore;
    const pk=t.scores.productKnowledge.score;
    const mp=t.scores.mapping.score;
    const ss=t.scores.softSkills.score;
    const pr=t.scores.presentability.score;
    const tech=t.scores.techScorePercent;
    const soft=t.scores.softScorePercent;
    const attendanceDays=t.attendance.attendanceDays;
    const absent=t.attendance.absent;

    // Build strengths and weaknesses
    const areas=[
        {name:'Product Knowledge',score:pk,max:5},
        {name:'Mapping',score:mp,max:5},
        {name:'Soft Skills',score:ss,max:5},
        {name:'Presentability',score:pr,max:5}
    ];
    const sorted=[...areas].sort((a,b)=>b.score-a.score);
    const strengths=sorted.filter(a=>a.score>=4);
    const weaknesses=sorted.filter(a=>a.score<4);
    const perfectAreas=sorted.filter(a=>a.score===a.max);

    let text=`${name} achieved ${article(res)} '${res}' result with an overall score of ${ov}%.`;

    // Tech sentence
    if(strengths.length>0){
        const strengthNames=strengths.map(a=>`${a.name} (${a.score}/${a.max})`);
        const verb=strengths.length>1?'demonstrated strong performance across':'demonstrated strong performance in';
        text+=` ${heOrShe(name)} ${verb} ${listify(strengthNames)}`;
        if(perfectAreas.length>0){
            text+=`, with perfect scores in ${listify(perfectAreas.map(a=>a.name))}`;
        }
        text+=`.`;
    }

    text+=` The Tech Score of ${tech}% reflects ${tech>=90?'outstanding':tech>=80?'solid':tech>=70?'good':tech>=60?'adequate':'limited'} technical competency`;
    if(weaknesses.length>0){
        text+=`, though there is room for improvement in ${listify(weaknesses.map(a=>`${a.name} (${a.score}/${a.max})`))}`;
    }
    text+=`.`;

    // Professionalism sentence
    text+=` Professional conduct was rated at ${soft}%`;
    if(soft>=90)text+=', reflecting excellent professionalism';
    else if(soft>=80)text+=', indicating strong professionalism';
    else if(soft>=70)text+=', showing good professional conduct';
    text+='.';

    // Attendance
    const missed=t.attendance.missedContent;
    const missedPct=(missed!=='N/A'&&missed!=null&&missed!=='')?parseInt(missed,10):null;
    if(absent===0&&attendanceDays!=='N/A'&&attendanceDays!=null){
        text+=` ${heOrShe(name)} maintained full attendance across ${attendanceDays} training day${attendanceDays!==1?'s':''} with no absences.`;
    }else if(absent===0){
        text+=` ${heOrShe(name)} maintained perfect attendance with no absences throughout the training period.`;
    }else if(attendanceDays!=='N/A'&&attendanceDays!=null){
        const totalDays=parseInt(attendanceDays,10)+absent;
        text+=` Attendance was ${attendanceDays} day${attendanceDays!==1?'s':''} out of ${totalDays} with ${absent} absence${absent!==1?'s':''}`;
        if(missedPct!=null&&missedPct>0){
            text+=`, resulting in ${missedPct}% missed content`;
        }
        text+='.';
    }else if(absent===1){
        text+=` ${heOrShe(name)} had 1 absence during the training period.`;
    }else if(absent>1){
        text+=` ${heOrShe(name)} had ${absent} absences during the training period${missedPct!=null&&missedPct>0?`, missing approximately ${missedPct}% of content`:''}`.trimEnd()+'.';
    }

    return text;
}

function article(r){return'AEIOU'.includes(r[0])?'an':'a'}
function heOrShe(name){
    // Simple heuristic — names ending in a/ah/ia are more likely female
    const n=name.trim().split(/\s+/)[0].toLowerCase();
    const femEndings=['a','ah','ia','na','da','ra','ya','ie','ey','een','ine','ina'];
    if(femEndings.some(e=>n.endsWith(e)))return'She';
    return'He';
}
function listify(arr){
    if(arr.length===0)return'';
    if(arr.length===1)return arr[0];
    if(arr.length===2)return arr[0]+' and '+arr[1];
    return arr.slice(0,-1).join(', ')+', and '+arr[arr.length-1];
}

function genComments(t){
    const pk=t.scores.productKnowledge.score;
    const mp=t.scores.mapping.score;
    const ss=t.scores.softSkills.score;
    const pr=t.scores.presentability.score;
    const ov=t.overallScore;

    const parts=[];
    if(ov>=90)parts.push('Outstanding overall performance');
    else if(ov>=80)parts.push('Good efforts');
    else if(ov>=70)parts.push('Decent performance');
    else if(ov>=60)parts.push('Acceptable performance');
    else parts.push('Needs significant improvement');

    // Strengths
    const high=[];
    if(pk>=4.5)high.push('technical knowledge');
    if(mp>=4.5)high.push('mapping skills');
    if(ss>=4.5)high.push('soft skills');
    if(pr>=4.5)high.push('presentability');
    if(high.length)parts.push('great '+listify(high));

    // Weaknesses
    const low=[];
    if(pk<3.5)low.push('product knowledge');
    if(mp<3.5)low.push('mapping');
    if(ss<3.5)low.push('soft skills');
    if(pr<3.5)low.push('presentability');
    if(low.length)parts.push('needs to focus more on '+listify(low));

    return parts.join(', ')+'.';
}

