// Update helpers
function uf(i,path,val){
    const ps=path.split('.');let o=S.trainees[i];
    for(let j=0;j<ps.length-1;j++)o=o[ps[j]];
    o[ps[ps.length-1]]=val;
    if(path==='rawAssessmentOutcome'){
        syncAssessmentState(S.trainees[i]);
        renderCards();
    }
}
function us(i,f,v){S.trainees[i].scores[f].score=clampScore(v)}

function recalc(i){
    const t=S.trainees[i];
    const pk=t.scores.productKnowledge.score,mp=t.scores.mapping.score;
    const ss=t.scores.softSkills.score,pr=t.scores.presentability.score;
    t.scores.totalCore=pk+mp;
    t.scores.techScorePercent=((pk+mp)/10)*100;
    t.scores.professionalConductRating.score=ss+pr;
    t.scores.softScorePercent=((ss+pr)/10)*100;
    t.overallScore=Math.round(((t.scores.techScorePercent+t.scores.softScorePercent)/2)*10)/10;

    // Auto-calculate Missed Content % from absent days and total training days
    const att=t.attendance.attendanceDays;
    const abs=t.attendance.absent;
    const attNum=(att!=='N/A'&&att!=null&&att!=='')?parseInt(att,10):null;
    const absNum=(abs!=null&&abs!==''&&!isNaN(parseInt(abs,10)))?parseInt(abs,10):0;
    if(attNum!=null&&attNum>=0){
        const totalDays=attNum+absNum;
        t.attendance.missedContent=totalDays>0?Math.round((absNum/totalDays)*100):0;
    }
    // If attendanceDays is unknown but we have absences, leave missedContent as-is

    syncAssessmentState(t);
    renderCards();
}

function recalcAll(){
    S.trainees.forEach((_,i)=>recalc(i));
    // Also regenerate text for all
    S.trainees.forEach((t,i)=>{
        if(t.name)t.overallAssessment=genAssessment(t);
        if(t.name&&!t.comments)t.comments=genComments(t);
    });
    renderCards();
    toast('All scores & text recalculated!','ok');
}

function regenText(i){
    const t=S.trainees[i];
    if(!t.name){toast('Enter trainee name first','err');return}
    recalc(i);
    t.overallAssessment=genAssessment(t);
    renderCards();toast('Assessment generated!','ok');
}

function regenComments(i){
    const t=S.trainees[i];
    if(!t.name){toast('Enter trainee name first','err');return}
    recalc(i);
    t.comments=genComments(t);
    renderCards();toast('Comments generated!','ok');
}

// ============================================================
//  STEP 4 — GENERATE REPORT
// ============================================================
function genReport(){
    const empty=S.trainees.filter(t=>!t.name.trim());
    if(empty.length){toast('Fill in all trainee names first','err');return}

    // Auto-generate any missing text
    S.trainees.forEach((t,i)=>{
        recalc(i);
        if(!t.overallAssessment)t.overallAssessment=genAssessment(t);
        if(!t.comments)t.comments=genComments(t);
    });

    const c=document.getElementById('all-pages');
    let html=mkIntro();
    S.trainees.forEach(t=>{html+=mkPage(t)});
    html+=mkOutro();
    c.innerHTML=html;
    document.getElementById('rtag').textContent=`${S.co} — Batch ${S.batch} — ${S.trainees.length} Trainee(s)`;
    go(4);toast('Report generated!','ok');
}

