function fmtDate(){return new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'})}
function cprt(){return`\u00A9 ${new Date().getFullYear()} RED Real Estate Domain Training Academy. All rights reserved.`}

