function mkIntro(){
    return`<div class="page"><div class="cover-layout"><div class="cover-sidebar"><h2>RED</h2></div><div class="cover-content">
    <div class="cover-logo">${LOGO}</div>
    <div class="cover-title"><h1 class="text-dark">Trainee Performance</h1><h1 class="text-red">Report</h1></div>
    <div class="cover-info">
        <div class="cover-info-row"><span class="cover-info-label">Company Name</span><span class="cover-info-value">${ee(S.co)}</span></div>
        <div class="cover-info-row"><span class="cover-info-label">Batch Number</span><span class="cover-info-value">${ee(S.batch)}</span></div>
        <div class="cover-info-row"><span class="cover-info-label">Number of Trainees</span><span class="cover-info-value">${S.trainees.length}</span></div>
    </div>
    <div class="cover-footer"><p>Report Generated on: ${fmtDate()}</p><p>${cprt()}</p></div>
    </div></div></div>`;
}

function mkPage(t){
    const outcomeLabel=displayAssessmentOutcome(t)||t.assessmentResult;
    const ld=(t.attendance.late==='N/A'||t.attendance.late==null)?'N/A':`${t.attendance.late} Days`;
    const ad=(t.attendance.attendanceDays==='N/A'||t.attendance.attendanceDays==null)?'N/A':`${t.attendance.attendanceDays} Day${t.attendance.attendanceDays!==1?'s':''}`;
    const md=(t.attendance.missedContent==='N/A'||t.attendance.missedContent==null)?'N/A':`${t.attendance.missedContent}%`;
    const tcm=t.scores.mapping.max+t.scores.productKnowledge.max;
    const cm=t.scores.presentability.max+t.scores.softSkills.max;
    const sc=t.assessmentResult==='Failed'?'score-red':'score-green';
    const dc=(t.attendance.attendanceDays==='N/A'||t.attendance.attendanceDays==null)?'text-na':'text-aok';
    const lc=(t.attendance.late==='N/A'||t.attendance.late==null)?'text-na':(t.attendance.late==0?'text-aok':'text-aw');
    const ac=t.attendance.absent===0?'text-aok':'text-aw';
    const mc=(t.attendance.missedContent==='N/A'||t.attendance.missedContent==null)?'text-na':(t.attendance.missedContent==0?'text-aok':'text-aw');
    return`<div class="page">
    <div class="report-header"><div class="report-header-logo">${LOGO}</div><div class="report-header-right"><h1>Trainee Performance Report</h1><p>${ee(t.batch)}</p></div></div>
    <div class="report-body">
        <div class="details-card"><div><h3>Trainee Details</h3><p><span class="label">Name:</span> ${ee(t.name)}</p><p><span class="label">Company:</span> ${ee(t.company)}</p></div>
        <div style="text-align:right"><h3>Overall Performance</h3><div class="score-big ${sc}">${t.overallScore}<span>%</span></div><div class="badge ${t.badgeClass}">${ee(outcomeLabel)}</div></div></div>
        <h3 class="section-title">Overall Assessment</h3><div class="assessment-box"><p>${ee(t.overallAssessment)}</p></div>
        <div class="two-col"><div>
            <h3 class="section-title">Detailed Score Breakdown</h3>
            <table class="data-table"><thead><tr><th>Performance Area</th><th>Score</th></tr></thead><tbody>
                <tr><td>Product Knowledge</td><td>${t.scores.productKnowledge.score} out of ${t.scores.productKnowledge.max}</td></tr>
                <tr><td>Mapping</td><td>${t.scores.mapping.score} out of ${t.scores.mapping.max}</td></tr>
                <tr class="row-total"><td>Total (Core Skills)</td><td>${t.scores.totalCore} out of ${tcm}</td></tr>
                <tr class="row-pct row-pct-b"><td>Tech Score %</td><td>${t.scores.techScorePercent}%</td></tr>
                <tr><td>Soft Skills</td><td>${t.scores.softSkills.score} out of ${t.scores.softSkills.max}</td></tr>
                <tr><td>Presentability</td><td>${t.scores.presentability.score} out of ${t.scores.presentability.max}</td></tr>
                <tr class="row-total"><td>Professional Conduct Rating</td><td>${t.scores.professionalConductRating.score} out of ${cm}</td></tr>
                <tr class="row-pct"><td>Professionalism Score %</td><td>${t.scores.softScorePercent}%</td></tr>
            </tbody></table>
        </div><div>
            <h3 class="section-title">Attendance & Professionalism</h3>
            <table class="data-table"><thead><tr><th>Metric</th><th>Record</th></tr></thead><tbody>
                <tr><td>Attendance Days</td><td class="${dc}">${ad}</td></tr>
                <tr><td>Punctuality (Late Arrivals)</td><td class="${lc}">${ld}</td></tr>
                <tr><td>Attendance (Absent Days)</td><td class="${ac}">${t.attendance.absent} Day${t.attendance.absent!==1?'s':''}</td></tr>
                <tr><td>Missed Content Percentage</td><td class="${mc}">${md}</td></tr>
            </tbody></table>
        </div></div>
        <h3 class="section-title">Trainer's Comments</h3><div class="comments-box"><p>"${ee(t.comments)}"</p></div>
    </div>
    <div class="report-footer"><p>Report Generated on: ${fmtDate()}</p><p>${cprt()}</p></div>
    </div>`;
}

function mkOutro(){
    const names=S.trainees.map(t=>t.name);
    const nl=listify(names);
    const p1=`This report concludes the performance evaluation for the ${S.trainees.length>1?S.trainees.length+' trainees':'trainee'}: ${nl}.`;
    const tiers={Aced:[],Excellent:[],Good:[],Passed:[],Failed:[]};
    S.trainees.forEach(t=>{if(tiers[t.assessmentResult])tiers[t.assessmentResult].push(t)});
    const fmt=a=>listify(a.map(t=>t.name));
    const fmtS=a=>listify(a.map(t=>t.overallScore+'%'));
    let p2=[];
    if(tiers.Aced.length)p2.push(`We are pleased to report that ${fmt(tiers.Aced)} achieved an 'Aced' result with ${tiers.Aced.length>1?'scores':'a score'} of ${fmtS(tiers.Aced)}. Their outstanding performance confirms their readiness to immediately begin professional roles in the real estate domain.`);
    if(tiers.Excellent.length)p2.push(`${fmt(tiers.Excellent)} achieved an 'Excellent' result with ${tiers.Excellent.length>1?'scores':'a score'} of ${fmtS(tiers.Excellent)}, demonstrating strong overall competency and a high level of professionalism.`);
    if(tiers.Good.length)p2.push(`${fmt(tiers.Good)} received a 'Good' assessment with ${tiers.Good.length>1?'scores':'a score'} of ${fmtS(tiers.Good)}, showing solid foundational skills and readiness for practical application.`);
    if(tiers.Passed.length)p2.push(`${fmt(tiers.Passed)} achieved a 'Passed' result with ${tiers.Passed.length>1?'scores':'a score'} of ${fmtS(tiers.Passed)}, meeting the minimum competency requirements.`);
    if(tiers.Failed.length)p2.push(`However, ${fmt(tiers.Failed)} did not meet the passing criteria and ${tiers.Failed.length>1?'are':'is'} required to re-attend the training program.`);
    return`<div class="page"><div class="cover-layout"><div class="cover-sidebar"><h2>RED</h2></div><div class="cover-content">
    <div class="cover-logo">${LOGO}</div>
    <div class="cover-title"><h1 class="text-dark">Concluding</h1><h1 class="text-red">Remarks</h1></div>
    <div class="outro-text"><p>${ee(p1)}</p><p>${ee(p2.join(' '))}</p></div>
    <div class="quote-section"><div class="quote-label">A Final Thought</div><div class="quote-text">"The only way to do great work is to love what you do."</div><div class="quote-author">&mdash; Steve Jobs</div></div>
    <div class="cover-footer"><p>Report Generated on: ${fmtDate()}</p><p>${cprt()}</p></div>
    </div></div></div>`;
}

// ============================================================
//  PDF DOWNLOAD
// ============================================================
async function dlPDF(){
    const pages=document.querySelectorAll('#all-pages .page');
    if(!pages.length){toast('No report','err');return}
    const ov=document.getElementById('pdf-overlay'),bar=document.getElementById('pdf-bar'),txt=document.getElementById('pdf-txt');
    ov.classList.add('on');
    try{
        const{jsPDF}=window.jspdf;
        const pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
        for(let i=0;i<pages.length;i++){
            txt.textContent=`Rendering page ${i+1} of ${pages.length}...`;
            bar.style.width=((i+1)/pages.length*100)+'%';
            const canvas=await html2canvas(pages[i],{scale:2,useCORS:true,backgroundColor:'#fff',logging:false});
            if(i>0)pdf.addPage();
            pdf.addImage(canvas.toDataURL('image/jpeg',.95),'JPEG',0,0,210,297);
        }
        pdf.save(`Xcelias_Report_${S.co.replace(/\s+/g,'_')}_Batch${S.batch}.pdf`);
        toast('PDF downloaded!','ok');
    }catch(e){console.error(e);toast('PDF failed — try Print instead','err')}
    finally{ov.classList.remove('on');bar.style.width='0%'}
}

function startOver(){
    if(!confirm('Start new report? All data cleared.'))return;
    S.trainees=[];S.imgs=[];S.maxStep=1;
    document.getElementById('gallery').innerHTML='';
    document.getElementById('all-pages').innerHTML='';
    go(1);toast('Ready for new report','info');
}